//! Wasm entrypoint for Monster Studio source-to-target face transfer.

use wasm_bindgen::prelude::*;

use crate::face_to_face_swap::{
    face_to_face_swap_rgb_f32, face_to_face_swap_rgb_f32_v2, face_to_face_swap_rgb_f32_v3,
    FaceSwapAnchor, FaceSwapBox, FaceSwapLandmarks, FaceSwapV3Params, FaceToFaceSwapConfig,
    PrevTargetFrame,
};

#[wasm_bindgen]
pub struct WasmFaceToFaceSwapResult {
    #[wasm_bindgen(skip)]
    rgb: Vec<f32>,
    #[wasm_bindgen(skip)]
    alpha: Vec<f32>,
    #[wasm_bindgen(skip)]
    certificate_json: String,
}

#[wasm_bindgen]
impl WasmFaceToFaceSwapResult {
    #[wasm_bindgen(getter)]
    pub fn rgb(&self) -> Vec<f32> {
        self.rgb.clone()
    }

    #[wasm_bindgen(getter)]
    pub fn alpha(&self) -> Vec<f32> {
        self.alpha.clone()
    }

    #[wasm_bindgen(getter)]
    pub fn certificate_json(&self) -> String {
        self.certificate_json.clone()
    }
}

fn optional_point(x: f32, y: f32) -> Option<(f32, f32)> {
    if x.is_finite() && y.is_finite() && x >= 0.0 && y >= 0.0 {
        Some((x, y))
    } else {
        None
    }
}

fn anchors_from_flat(flat: &[f32]) -> Vec<FaceSwapAnchor> {
    let mut anchors = Vec::new();
    for chunk in flat.chunks_exact(4) {
        let x = chunk[0];
        let y = chunk[1];
        let role = chunk[2];
        let confidence = chunk[3];
        if x.is_finite() && y.is_finite() && role.is_finite() && confidence.is_finite() {
            anchors.push(FaceSwapAnchor {
                x,
                y,
                role: role.clamp(0.0, 255.0).round() as u8,
                confidence: confidence.clamp(0.0, 1.0),
            });
        }
    }
    anchors
}

/// Source-to-target face transfer over row-major unit RGB buffers.
///
/// Optional landmark coordinates should be passed as negative values when absent.
#[wasm_bindgen(js_name = wasmFaceToFaceSwapRgbF32)]
#[allow(clippy::too_many_arguments)]
pub fn wasm_face_to_face_swap_rgb_f32(
    source_rgb: &[f32],
    source_width: u32,
    source_height: u32,
    target_rgb: &[f32],
    target_width: u32,
    target_height: u32,
    source_x: f32,
    source_y: f32,
    source_w: f32,
    source_h: f32,
    target_x: f32,
    target_y: f32,
    target_w: f32,
    target_h: f32,
    source_left_eye_x: f32,
    source_left_eye_y: f32,
    source_right_eye_x: f32,
    source_right_eye_y: f32,
    source_mouth_x: f32,
    source_mouth_y: f32,
    target_left_eye_x: f32,
    target_left_eye_y: f32,
    target_right_eye_x: f32,
    target_right_eye_y: f32,
    target_mouth_x: f32,
    target_mouth_y: f32,
    blend_strength: f32,
) -> Result<WasmFaceToFaceSwapResult, JsError> {
    let mut config = FaceToFaceSwapConfig::default();
    config.blend_strength = blend_strength;
    let result = face_to_face_swap_rgb_f32(
        source_rgb,
        source_width,
        source_height,
        target_rgb,
        target_width,
        target_height,
        FaceSwapBox {
            x: source_x,
            y: source_y,
            w: source_w,
            h: source_h,
        },
        FaceSwapBox {
            x: target_x,
            y: target_y,
            w: target_w,
            h: target_h,
        },
        FaceSwapLandmarks {
            left_eye: optional_point(source_left_eye_x, source_left_eye_y),
            right_eye: optional_point(source_right_eye_x, source_right_eye_y),
            mouth: optional_point(source_mouth_x, source_mouth_y),
        },
        FaceSwapLandmarks {
            left_eye: optional_point(target_left_eye_x, target_left_eye_y),
            right_eye: optional_point(target_right_eye_x, target_right_eye_y),
            mouth: optional_point(target_mouth_x, target_mouth_y),
        },
        &config,
    )
    .map_err(|e| JsError::new(&format!("face_to_face_swap: {}", e)))?;
    let certificate_json = serde_json::to_string(&result.certificate)
        .map_err(|e| JsError::new(&format!("json: {}", e)))?;
    Ok(WasmFaceToFaceSwapResult {
        rgb: result.rgb,
        alpha: result.alpha,
        certificate_json,
    })
}

/// V2 source-to-target transfer with flattened anchors `[x,y,role,confidence]*`.
#[wasm_bindgen(js_name = wasmFaceToFaceSwapRgbF32V2)]
#[allow(clippy::too_many_arguments)]
pub fn wasm_face_to_face_swap_rgb_f32_v2(
    source_rgb: &[f32],
    source_width: u32,
    source_height: u32,
    target_rgb: &[f32],
    target_width: u32,
    target_height: u32,
    source_x: f32,
    source_y: f32,
    source_w: f32,
    source_h: f32,
    target_x: f32,
    target_y: f32,
    target_w: f32,
    target_h: f32,
    source_left_eye_x: f32,
    source_left_eye_y: f32,
    source_right_eye_x: f32,
    source_right_eye_y: f32,
    source_mouth_x: f32,
    source_mouth_y: f32,
    target_left_eye_x: f32,
    target_left_eye_y: f32,
    target_right_eye_x: f32,
    target_right_eye_y: f32,
    target_mouth_x: f32,
    target_mouth_y: f32,
    blend_strength: f32,
    source_anchors: &[f32],
    target_anchors: &[f32],
    deblur_admission_blend: f32,
) -> Result<WasmFaceToFaceSwapResult, JsError> {
    let mut config = FaceToFaceSwapConfig::default();
    config.blend_strength = blend_strength;
    config.deblur_admission_blend = deblur_admission_blend.clamp(0.0, 1.0);
    let source_anchor_vec = anchors_from_flat(source_anchors);
    let target_anchor_vec = anchors_from_flat(target_anchors);
    let result = face_to_face_swap_rgb_f32_v2(
        source_rgb,
        source_width,
        source_height,
        target_rgb,
        target_width,
        target_height,
        FaceSwapBox {
            x: source_x,
            y: source_y,
            w: source_w,
            h: source_h,
        },
        FaceSwapBox {
            x: target_x,
            y: target_y,
            w: target_w,
            h: target_h,
        },
        FaceSwapLandmarks {
            left_eye: optional_point(source_left_eye_x, source_left_eye_y),
            right_eye: optional_point(source_right_eye_x, source_right_eye_y),
            mouth: optional_point(source_mouth_x, source_mouth_y),
        },
        FaceSwapLandmarks {
            left_eye: optional_point(target_left_eye_x, target_left_eye_y),
            right_eye: optional_point(target_right_eye_x, target_right_eye_y),
            mouth: optional_point(target_mouth_x, target_mouth_y),
        },
        &source_anchor_vec,
        &target_anchor_vec,
        &config,
    )
    .map_err(|e| JsError::new(&format!("face_to_face_swap_v2: {}", e)))?;
    let certificate_json = serde_json::to_string(&result.certificate)
        .map_err(|e| JsError::new(&format!("json: {}", e)))?;
    Ok(WasmFaceToFaceSwapResult {
        rgb: result.rgb,
        alpha: result.alpha,
        certificate_json,
    })
}

/// V3 eye-bar transfer. Same shape as V2 plus:
/// - `params`: flat `[color_transfer_strength, temporal_smoothing,
///   confidence_floor, seam_correction]`; missing/NaN entries fall back to
///   kernel defaults.
/// - `prev_target_frame`: empty slice for none, else the previous frame's
///   certificate echo `[cx, cy, d, rot, yaw]` (normalized units).
#[wasm_bindgen(js_name = wasmFaceToFaceSwapRgbF32V3)]
#[allow(clippy::too_many_arguments)]
pub fn wasm_face_to_face_swap_rgb_f32_v3(
    source_rgb: &[f32],
    source_width: u32,
    source_height: u32,
    target_rgb: &[f32],
    target_width: u32,
    target_height: u32,
    source_x: f32,
    source_y: f32,
    source_w: f32,
    source_h: f32,
    target_x: f32,
    target_y: f32,
    target_w: f32,
    target_h: f32,
    source_left_eye_x: f32,
    source_left_eye_y: f32,
    source_right_eye_x: f32,
    source_right_eye_y: f32,
    source_mouth_x: f32,
    source_mouth_y: f32,
    target_left_eye_x: f32,
    target_left_eye_y: f32,
    target_right_eye_x: f32,
    target_right_eye_y: f32,
    target_mouth_x: f32,
    target_mouth_y: f32,
    blend_strength: f32,
    source_anchors: &[f32],
    target_anchors: &[f32],
    deblur_admission_blend: f32,
    params: &[f32],
    prev_target_frame: &[f32],
) -> Result<WasmFaceToFaceSwapResult, JsError> {
    let mut config = FaceToFaceSwapConfig::default();
    config.blend_strength = blend_strength;
    config.deblur_admission_blend = deblur_admission_blend.clamp(0.0, 1.0);
    let defaults = FaceSwapV3Params::default();
    let param_or = |index: usize, fallback: f32| -> f32 {
        params
            .get(index)
            .copied()
            .filter(|value| value.is_finite())
            .unwrap_or(fallback)
    };
    let v3_params = FaceSwapV3Params {
        color_transfer_strength: param_or(0, defaults.color_transfer_strength),
        temporal_smoothing: param_or(1, defaults.temporal_smoothing),
        confidence_floor: param_or(2, defaults.confidence_floor),
        seam_correction: param_or(3, defaults.seam_correction),
        spill_strength: param_or(4, defaults.spill_strength),
    };
    let prev: Option<PrevTargetFrame> = if prev_target_frame.len() >= 5
        && prev_target_frame[..5].iter().all(|value| value.is_finite())
    {
        Some([
            prev_target_frame[0],
            prev_target_frame[1],
            prev_target_frame[2],
            prev_target_frame[3],
            prev_target_frame[4],
        ])
    } else {
        None
    };
    let source_anchor_vec = anchors_from_flat(source_anchors);
    let target_anchor_vec = anchors_from_flat(target_anchors);
    let result = face_to_face_swap_rgb_f32_v3(
        source_rgb,
        source_width,
        source_height,
        target_rgb,
        target_width,
        target_height,
        FaceSwapBox {
            x: source_x,
            y: source_y,
            w: source_w,
            h: source_h,
        },
        FaceSwapBox {
            x: target_x,
            y: target_y,
            w: target_w,
            h: target_h,
        },
        FaceSwapLandmarks {
            left_eye: optional_point(source_left_eye_x, source_left_eye_y),
            right_eye: optional_point(source_right_eye_x, source_right_eye_y),
            mouth: optional_point(source_mouth_x, source_mouth_y),
        },
        FaceSwapLandmarks {
            left_eye: optional_point(target_left_eye_x, target_left_eye_y),
            right_eye: optional_point(target_right_eye_x, target_right_eye_y),
            mouth: optional_point(target_mouth_x, target_mouth_y),
        },
        &source_anchor_vec,
        &target_anchor_vec,
        &v3_params,
        prev,
        &config,
    )
    .map_err(|e| JsError::new(&format!("face_to_face_swap_v3: {}", e)))?;
    let certificate_json = serde_json::to_string(&result.certificate)
        .map_err(|e| JsError::new(&format!("json: {}", e)))?;
    Ok(WasmFaceToFaceSwapResult {
        rgb: result.rgb,
        alpha: result.alpha,
        certificate_json,
    })
}
